module custom_logic (
    input x,
    input y,
    input z,
    input a,
    output reg invalid);

    always @(*) begin
        case ({x, y, z, a})
            4'b1010: invalid = 1;
            4'b0101: invalid = 0;
            4'b1111: invalid = 1;
            4'b0000: invalid = 0;
            4'b1001: invalid = 1;
            4'b0110: invalid = 0;
            4'b1101: invalid = 1;
            4'b0010: invalid = 1;
            4'b1011: invalid = 0;
            4'b0100: invalid = 1;
            default: invalid = 0;
        endcase
    end
endmodule
